```javascript
function solve(nums, queries) {
    class FenwickTree {
        constructor(size) {
            this.n = size;
            this.tree = new Array(this.n + 1).fill(0);
        }

        update(index, delta) {
            while (index <= this.n) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }

        query(index) {
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }

        rangeQuery(l, r) {
            return this.query(r) - this.query(l - 1);
        }
    }

    const n = nums.length;
    const max_k = 5;

    function popcount(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    function getDepth(x) {
        let depth = 0;
        while (x !== 1) {
            x = popcount(x);
            depth++;
        }
        return depth;
    }

    const fenwickTrees = [];
    for (let k = 0; k <= 5; k++) {
        fenwickTrees[k] = new FenwickTree(n);
    }

    // Initialize the Fenwick Trees
    for (let i = 0; i < n; i++) {
        const d = getDepth(nums[i]);
        if (d <= 5) {
            fenwickTrees[d].update(i + 1, 1);
        }
    }

    const answer = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k = q[3];
            if (k > 5) {
                answer.push(0);
                continue;
            }
            const tree = fenwickTrees[k];
            const res = tree.rangeQuery(l + 1, r + 1);
            answer.push(res);
        } else {
            const idx = q[1];
            const val = q[2];
            const old_val = nums[idx];
            const old_depth = getDepth(old_val);
            fenwickTrees[old_depth].update(idx + 1, -1);
            nums[idx] = val;
            const new_depth = getDepth(val);
            fenwickTrees[new_depth].update(idx + 1, 1);
        }
    }

    return answer;
}
